    val n = s.length
    var base = 0L
    var countL = 0L
    var countLC = 0L
    for (char in s) {
        when (char) {
            'L' -> {
                countL++
            }
            'C' -> {
                countLC += countL
            }
            'T' -> {
                base += countLC
            }
        }
    }
    val suffixCT = LongArray(n + 2) { 0 }
    var countT = 0L
    for (i in n - 1 downTo 0) {
        suffixCT[i] = suffixCT[i + 1]
        if (s[i] == 'T') {
            countT++
        } else if (s[i] == 'C') {
            suffixCT[i] += countT
        }
    }
    val prefixL = LongArray(n + 1) { 0 }
    for (i in 0 until n) {
        prefixL[i + 1] = prefixL[i] + if (s[i] == 'L') 1L else 0L
    }
    val suffixT = LongArray(n + 2) { 0 }
    for (i in n - 1 downTo 0) {
        suffixT[i] = suffixT[i + 1] + if (s[i] == 'T') 1 else 0
    }
    val prefixLC = LongArray(n + 1) { 0 }
    var curCountL = 0L
    for (i in 0 until n) {
        prefixLC[i + 1] = prefixLC[i]
        if (s[i] == 'L') {
            curCountL++
        } else if (s[i] == 'C') {
            prefixLC[i + 1] = prefixLC[i] + curCountL
        }
    }
    var ans = base
    for (i in 0..n) {
        val candidateL = base + suffixCT[i]
        val candidateC = base + prefixL[i] * suffixT[i]
        val candidateT = base + prefixLC[i]
        ans = maxOf(ans, candidateL, candidateC, candidateT)
    }
    return ans
}
