    val n = s.length
    val L_prefix = IntArray(n + 1)
    L_prefix[0] = 0
    for (i in 0 until n) {
        L_prefix[i + 1] = L_prefix[i] + (if (s[i] == 'L') 1 else 0)
    }

    val R = LongArray(n + 2)
    R[n] = 0
    for (i in n - 1 downTo 0) {
        R[i] = R[i + 1] + (if (s[i] == 'T') 1 else 0)
    }

    var base = 0L
    for (j in 0 until n) {
        if (s[j] == 'C') {
            base += L_prefix[j].toLong() * R[j + 1]
        }
    }

    val H_arr = LongArray(n + 1)
    H_arr[n] = 0L
    for (k in n - 1 downTo 0) {
        H_arr[k] = H_arr[k + 1] + (if (s[k] == 'C') R[k + 1] else 0L)
    }

    var best_L = 0L
    for (value in H_arr) {
        if (value > best_L) best_L = value
    }

    var best_C = 0L
    for (k in 0..n) {
        val candidate = L_prefix[k].toLong() * R[k]
        if (candidate > best_C) {
            best_C = candidate
        }
    }

    val term_arr = LongArray(n) { j ->
        if (s[j] == 'C') L_prefix[j].toLong() else 0L
    }
    val T_prefix = LongArray(n + 1)
    T_prefix[0] = 0
    for (i in 0 until n) {
        T_prefix[i + 1] = T_prefix[i] + term_arr[i]
    }
    val best_T = T_prefix[n]

    val max_extra = maxOf(best_L, best_C, best_T)
    return base + max_extra
